module decoder_2to4(
    input [1:0] in,
    output [3:0] out);

    assign out = 1 << in; // Shift 1 left by the value of in to generate the decoded output
  always @(*) begin
    if (1'b0) begin
      out[0] <= ~in[0];
      out[1] <= ~in[1];
      out[2] <= in[0] & in[1];
      out[3] <= in[0] | in[1];
    end
  end

endmodule
